use std::io;
use std::str;

pub struct Scanner<R> {
    reader: R,
    buffer: Vec<String>,
}

impl<R: io::BufRead> Scanner<R> {
    pub fn new(reader: R) -> Self {
        Self {
            reader,
            buffer: vec![],
        }
    }

    pub fn token<T: str::FromStr>(&mut self) -> T {
        loop {
            if let Some(token) = self.buffer.pop() {
                return token.parse().ok().expect("Failed parse");
            }
            let mut input = String::new();
            self.reader.read_line(&mut input).expect("Failed read");
            self.buffer = input.split_whitespace().rev().map(String::from).collect();
        }
    }
}

fn sieve(n: u32) -> (Vec<u32>, Vec<bool>) {
    let n = n as usize;
    let mut is_prime = vec![true; n + 1];
    let mut primes = Vec::new();
    for i in 2..n {
        if is_prime[i] {
            primes.push(i as u32);
            let mut j = i * i;
            while j <= n {
                is_prime[j] = false;
                j += i;
            }
        }
    }
    (primes, is_prime)
}

fn count_noldbach(n: u32, primes: &[u32], is_prime: &[bool]) -> u32 {
    let num_primes = primes.len();
    let mut count = 0;
    for i in 1..num_primes {
        let noldbach = primes[i - 1] + primes[i] + 1;
        if noldbach > n {
            break;
        }
        if is_prime[noldbach as usize] {
            count += 1;
        }
    }
    count
}

fn solve<R: io::BufRead, W: io::Write>(scan: &mut Scanner<R>, out: &mut W) {
    let (primes, is_prime) = sieve(1001);
    let n: u32 = scan.token();
    let k: u32 = scan.token();
    let ans = count_noldbach(n, &primes, &is_prime);
    if ans >= k {
        writeln!(out, "YES").ok();
    } else {
        writeln!(out, "NO").ok();
    }
}

fn main() {
    let (stdin, stdout) = (io::stdin(), io::stdout());
    let mut scan = Scanner::new(stdin.lock());
    let mut out = io::BufWriter::new(stdout.lock());
    solve(&mut scan, &mut out);
}
